import numpy as np


def init_weights(fan_in, fan_out, strategy, seed=0):
    """Initialize a (fan_out, fan_in) weight matrix with a named strategy."""
    if strategy == "zero":
        return np.zeros((fan_out, fan_in), dtype=float)

    if strategy == "random":
        std = 1.0
    elif strategy == "xavier":
        std = np.sqrt(2.0 / (fan_in + fan_out))
    elif strategy == "kaiming":
        std = np.sqrt(2.0 / fan_in)
    else:
        raise ValueError(f"unknown strategy: {strategy}")

    rng = np.random.default_rng(seed)
    return rng.standard_normal((fan_out, fan_in)) * std
